import{_ as a,o,c as r,ae as s}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"QR Codes Overview","description":"","frontmatter":{"title":"QR Codes Overview","slug":"qr-codes-overview"},"headers":[],"relativePath":"marketer-hub/qr-codes-overview.md","filePath":"marketer-hub/qr-codes-overview.md"}'),t={name:"marketer-hub/qr-codes-overview.md"};function i(l,e,n,c,p,d){return o(),r("div",null,[...e[0]||(e[0]=[s('<p>.png &quot;QR Codes.png&quot;)</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch QR Codes leverage existing channels like physical store locations, store receipts, flyers, direct mail campaigns, product packaging, print media, desktop website, and even over-the-top channels. You can use them to reach various user segments to convert them into loyal app users. By using Branch QR Codes to reach new users and bring your existing user base into the app, you can unlock greater user LTV, in-app revenue, and hit your app growth goals.</p><h3 id="qr-codes-use-cases" tabindex="-1">QR Codes Use Cases <a class="header-anchor" href="#qr-codes-use-cases" aria-label="Permalink to &quot;QR Codes Use Cases&quot;">​</a></h3><ul><li><p>In-Store Signage, Posters, Flyers, etc.</p></li><li><p>Purchase Materials (receipts, bags, cups, etc.)</p></li><li><p>Physical Mailers</p></li><li><p>TV Ads</p></li><li><p>Email</p></li><li><p>Cross-Device Engagement:</p><ul><li>Desktop Web to App</li><li>Auto-Login</li><li>Referrals</li><li>Promotions, Coupons, etc</li><li>In-App Sharing</li></ul></li></ul><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li>User is presented with a QR code.</li><li>User uses their phone&#39;s camera to scan the QR code.</li><li>User is routed to the App/Play Store to download the app.</li><li>App install &amp; downstream app events are attributed to QR code.</li></ol><p>.png &quot;QR Example.png&quot;)</p><div class="tip custom-block"><p class="custom-block-title">QR Codes</p><p>To learn how to create QR Codes in Branch, view our guide <a href="./create-qr-codes.html">here</a>.</p></div><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>Access to Branch QR Codes requires a premium plan. Please <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more about pricing and availability.</p>',11)])])}const m=a(t,[["render",i]]);export{u as __pageData,m as default};
